import math
def generate_input(n):
    if not hasattr(generate_input, "_idx"):
        generate_input._idx = 0
    generate_input._idx += 1
    if generate_input._idx == 1:
        a = 1 + (n % 3)
        v = a + 3 + (n % 5)
        return f"{a} {v}"
    elif generate_input._idx == 2:
        a = 1 + (n % 3)
        v = a + 3 + (n % 5)
        l = 2 + (n % 5)
        d = max(1, l - 1)
        w = max(1, min(v, (d % (v + 1)) + 1))
        return f"{l} {d} {w}"
    else:
        return "1 1"
